import { FunctionalComponent, h, VNode } from '@stencil/core';

import { HeadlineLabelRendererProps, HeadlineSubtextRendererProps, TagLabelRendererProps, HeadlineBodyRendererProps, RenderCardBodyProps, RenderCardBulletsProps, ContentWrapperProps, TYPOGRAPHY_CLASSES } from '../models/card.model';
import { twMerge } from './utils';
import { CLASSES, TextStyles, resolveTextStyles } from './card-styles';

export { cardBaseClasses, cardXlargeBaseClasses, cardXlargePortraitBaseClasses, cardDisabledClasses, cardElevationClasses, cardNoElevationClasses, cardOnSurfaceClasses, cardOffSurfaceClasses, cardBaseBorderClasses, cardGhostBorderClasses } from './card-styles';

const RenderCardHeadlineLabel: FunctionalComponent<HeadlineLabelRendererProps> = ({ headlineLabel, customClass }) => {
  if (!headlineLabel) return null;

  return <div class={`${CLASSES.headlineLabel} ${customClass}`}>{headlineLabel}</div>;
};

const RenderCardHeadlineSubtext: FunctionalComponent<HeadlineSubtextRendererProps> = ({ headlineSubtext, customClass }) => {
  if (!headlineSubtext) return null;

  return <div class={`${CLASSES.headlineSubtext} ${customClass}`}>{headlineSubtext}</div>;
};

const RenderCardTagLabel: FunctionalComponent<TagLabelRendererProps> = ({ tagLabel, customClass }) => {
  if (!tagLabel) return null;

  return <div class={`${CLASSES.tagLabel} ${customClass}`}>{tagLabel}</div>;
};

const RenderCardHeadline: FunctionalComponent<HeadlineBodyRendererProps> = ({ headline, customClass, headingLevel = 'h3' }) => {
  if (!headline) return null;
  const Tag = headingLevel;

  return <Tag class={`${CLASSES.headline} ${customClass}`}>{headline}</Tag>;
};

const RenderCardBody: FunctionalComponent<RenderCardBodyProps> = ({ body, customClass }) => {
  if (!body) return null;

  return <p class={`${CLASSES.body} ${customClass}`}>{body}</p>;
};

const RenderCardBullets: FunctionalComponent<RenderCardBulletsProps> = ({ bullets, customClass, maxBullets = 3 }) => {
  if (!bullets || bullets.length === 0) return null;

  return (
    <ul class={`${CLASSES.bullet} ${customClass}`}>
      {bullets.slice(0, maxBullets).map((bullet, idx) => (
        <li class={`last:mb-0${idx !== 0 ? ' list-disc' : ''}`}>{bullet}</li>
      ))}
    </ul>
  );
};

type VariantRenderer = (props: ContentWrapperProps, styles: TextStyles) => VNode | null;

const RenderMicro: VariantRenderer = (props, styles) => {
  const { primaryHeadline, body, headingLevel = 'h1' } = props;
  const bodyClasses = primaryHeadline ? 'line-clamp-2 pt-050' : 'line-clamp-2 pt-0';

  return (
    <div class={CLASSES.micro}>
      {primaryHeadline && <RenderCardHeadline headline={primaryHeadline} headingLevel={headingLevel} customClass={`${styles.heading} heading-xxsmall-alt line-clamp-2`} />}
      {body && <RenderCardBody body={body} customClass={`${bodyClasses} ${styles.body} body-small`} />}
    </div>
  );
};

const RenderSmall: VariantRenderer = (props, styles) => {
  const { primaryHeadline, body, bullets, contentType, headingLevel = 'h1' } = props;

  return (
    <div class={CLASSES.small}>
      {primaryHeadline && <RenderCardHeadline headline={primaryHeadline} headingLevel={headingLevel} customClass={`${styles.heading} heading-xsmall-alt line-clamp-2`} />}
      {body && contentType === 'body' && <RenderCardBody body={body} customClass={`${styles.body} body-medium line-clamp-2`} />}
      {bullets?.length > 0 && contentType === 'stacked' && <RenderCardBullets bullets={bullets} customClass={`${styles.body} body-small`} />}
    </div>
  );
};

const RenderXlarge: VariantRenderer = (props, styles) => {
  const {
    primaryHeadline,
    headlineLabel,
    headlineSubtext,
    headingLevel = 'h1',
    tagLabel,
    isMobile,
    topPadding,
    headlineSize = 'xlarge',
    subHeadlineSize = 'large',
    tagSize = 'large',
  } = props;

  const headlineFontSize = isMobile ? 'title-small' : TYPOGRAPHY_CLASSES.headline[headlineSize];
  const subtextFontSize = isMobile ? 'body-small' : TYPOGRAPHY_CLASSES.subHeadline[subHeadlineSize];
  const tagFontSize = isMobile ? 'heading-small' : TYPOGRAPHY_CLASSES.tag[tagSize];
  const topPaddingClass = topPadding ? 'pt-500' : '';
  const labelStyles = twMerge(styles.disclaimer, topPaddingClass, 'font-component-accent tracking-12 leading-label-large component-small uppercase');

  return (
    <div class={CLASSES.small}>
      {headlineLabel && <RenderCardHeadlineLabel headlineLabel={headlineLabel} customClass={labelStyles} />}
      {primaryHeadline && <RenderCardHeadline headline={primaryHeadline} headingLevel={headingLevel} customClass={`${styles.heading} ${headlineFontSize} line-clamp-2`} />}
      {headlineSubtext && <RenderCardHeadlineSubtext headlineSubtext={headlineSubtext} customClass={`${styles.subtext} ${subtextFontSize}`} />}
      {tagLabel && <RenderCardTagLabel tagLabel={tagLabel} customClass={`${styles.tag} ${tagFontSize}`} />}
    </div>
  );
};

const RenderDefault: VariantRenderer = (props, styles) => {
  const { primaryHeadline, featureHeadline, headlineLabel, headlineSubtext, body, bullets, headingLevel = 'h1' } = props;

  return (
    <div class={CLASSES.generic}>
      {headlineLabel && <RenderCardHeadlineLabel headlineLabel={headlineLabel} customClass={styles.disclaimer} />}
      {primaryHeadline && <RenderCardHeadline headline={primaryHeadline} headingLevel={headingLevel} customClass={`${styles.heading} heading-xsmall-alt line-clamp-3`} />}
      {featureHeadline && <RenderCardHeadline headline={featureHeadline} headingLevel={headingLevel} customClass={`${styles.heading} heading-xsmall line-clamp-1`} />}
      {headlineSubtext && <RenderCardHeadlineSubtext headlineSubtext={headlineSubtext} customClass={styles.subtext} />}
      {bullets?.length > 0 && <RenderCardBullets bullets={bullets} customClass={`${styles.body} body-medium-alt`} />}
      {body && <RenderCardBody body={body} customClass={`${styles.body} body-medium line-clamp-3`} />}
      <div class={CLASSES.genericSlot}><slot /></div>
    </div>
  );
};

const variantRenderers: Record<string, VariantRenderer> = {
  micro: RenderMicro,
  small: RenderSmall,
  xlarge: RenderXlarge,
};

export const RenderCardContent: FunctionalComponent<ContentWrapperProps> = (props) => {
  const { variant, disabled, hasGradient, inverseColor } = props;
  const styles = resolveTextStyles(disabled, hasGradient || inverseColor);
  const render = variantRenderers[variant] ?? RenderDefault;

  return render(props, styles);
};
